import { describe, it, expect } from 'vitest';
import { extractUniqueVertices } from '../../../src/visual/generators/extractVertices';
import { hashRandomFromPosition } from '../../../src/visual/generators/subdivideEdges';
import { generatePolyhedronEdges } from '../../../src/visual/generators/polyhedraEdges';

// --- Helpers ---

/** Single edge from (0,0,0) to (1,0,0) — 2 vertices, 6 floats */
function singleEdge(): Float32Array {
  return new Float32Array([0, 0, 0, 1, 0, 0]);
}

/** Triangle edges: A-B, B-C, A-C sharing 3 unique vertices */
function triangleEdges(): Float32Array {
  // A=(0,0,0), B=(1,0,0), C=(0,1,0)
  return new Float32Array([
    0, 0, 0, 1, 0, 0,  // A-B
    1, 0, 0, 0, 1, 0,  // B-C
    0, 0, 0, 0, 1, 0,  // A-C
  ]);
}

describe('US-065: extractUniqueVertices', () => {
  it('T-065-01: returns correct vertexCount for a single edge (2 unique vertices)', () => {
    const result = extractUniqueVertices(singleEdge());
    expect(result.vertexCount).toBe(2);
  });

  it('T-065-02: deduplicates shared vertices in a triangle (3 edges → 3 unique vertices)', () => {
    const result = extractUniqueVertices(triangleEdges());
    expect(result.vertexCount).toBe(3);
  });

  it('T-065-03: positions array length equals vertexCount * 3', () => {
    const result = extractUniqueVertices(triangleEdges());
    expect(result.positions.length).toBe(result.vertexCount * 3);
  });

  it('T-065-04: aRandom array length equals vertexCount * 3', () => {
    const result = extractUniqueVertices(triangleEdges());
    expect(result.aRandom.length).toBe(result.vertexCount * 3);
  });

  it('T-065-05: positions output is a Float32Array', () => {
    const result = extractUniqueVertices(singleEdge());
    expect(result.positions).toBeInstanceOf(Float32Array);
  });

  it('T-065-06: aRandom output is a Float32Array', () => {
    const result = extractUniqueVertices(singleEdge());
    expect(result.aRandom).toBeInstanceOf(Float32Array);
  });

  it('T-065-07: all position values are finite', () => {
    const result = extractUniqueVertices(triangleEdges());
    for (let i = 0; i < result.positions.length; i++) {
      expect(Number.isFinite(result.positions[i])).toBe(true);
    }
  });

  it('T-065-08: all aRandom values are finite and in [0, 1)', () => {
    const result = extractUniqueVertices(triangleEdges());
    for (let i = 0; i < result.aRandom.length; i++) {
      expect(Number.isFinite(result.aRandom[i])).toBe(true);
      expect(result.aRandom[i]).toBeGreaterThanOrEqual(0);
      expect(result.aRandom[i]).toBeLessThan(1);
    }
  });

  it('T-065-09: aRandom uses hashRandomFromPosition (matches shared helper output)', () => {
    const edge = singleEdge();
    const result = extractUniqueVertices(edge);
    // First vertex at (0,0,0)
    const [r0, r1, r2] = hashRandomFromPosition(0, 0, 0);
    expect(result.aRandom[0]).toBeCloseTo(r0, 5);
    expect(result.aRandom[1]).toBeCloseTo(r1, 5);
    expect(result.aRandom[2]).toBeCloseTo(r2, 5);
  });

  it('T-065-10: empty input returns zero-length arrays', () => {
    const result = extractUniqueVertices(new Float32Array(0));
    expect(result.vertexCount).toBe(0);
    expect(result.positions.length).toBe(0);
    expect(result.aRandom.length).toBe(0);
  });

  it('T-065-11: icosahedron edges (30 edges = 60 endpoints) yield exactly 12 unique vertices', () => {
    const edgeData = generatePolyhedronEdges({ shape: 'icosahedron', seed: 'ico-vertex-test' });
    const result = extractUniqueVertices(edgeData.positions);
    expect(result.vertexCount).toBe(12);
  });

  it('T-065-12: tetrahedron edges (6 edges = 12 endpoints) yield exactly 4 unique vertices', () => {
    const edgeData = generatePolyhedronEdges({ shape: 'tetrahedron', seed: 'tet-vertex-test' });
    const result = extractUniqueVertices(edgeData.positions);
    expect(result.vertexCount).toBe(4);
  });

  it('T-065-13: octahedron edges (12 edges = 24 endpoints) yield exactly 6 unique vertices', () => {
    const edgeData = generatePolyhedronEdges({ shape: 'octahedron', seed: 'oct-vertex-test' });
    const result = extractUniqueVertices(edgeData.positions);
    expect(result.vertexCount).toBe(6);
  });

  it('T-065-14: cube edges (12 edges = 24 endpoints) yield exactly 8 unique vertices', () => {
    const edgeData = generatePolyhedronEdges({ shape: 'cube', seed: 'cube-vertex-test' });
    const result = extractUniqueVertices(edgeData.positions);
    expect(result.vertexCount).toBe(8);
  });

  it('T-065-15: dodecahedron edges (30 edges = 60 endpoints) yield exactly 20 unique vertices', () => {
    const edgeData = generatePolyhedronEdges({ shape: 'dodecahedron', seed: 'dodec-vertex-test' });
    const result = extractUniqueVertices(edgeData.positions);
    expect(result.vertexCount).toBe(20);
  });

  it('T-065-16: extracted positions are a subset of input edge endpoint positions', () => {
    const edgeData = generatePolyhedronEdges({ shape: 'icosahedron', seed: 'subset-test' });
    const result = extractUniqueVertices(edgeData.positions);
    // Build set of input positions (rounded for comparison)
    const inputPosSet = new Set<string>();
    for (let i = 0; i < edgeData.positions.length; i += 3) {
      const key = `${Math.round(edgeData.positions[i] * 1e6)},${Math.round(edgeData.positions[i + 1] * 1e6)},${Math.round(edgeData.positions[i + 2] * 1e6)}`;
      inputPosSet.add(key);
    }
    for (let i = 0; i < result.positions.length; i += 3) {
      const key = `${Math.round(result.positions[i] * 1e6)},${Math.round(result.positions[i + 1] * 1e6)},${Math.round(result.positions[i + 2] * 1e6)}`;
      expect(inputPosSet.has(key), `extracted vertex not found in input: ${key}`).toBe(true);
    }
  });

  it('T-065-17: deterministic — same input produces same output', () => {
    const edgeData = generatePolyhedronEdges({ shape: 'icosahedron', seed: 'det-test' });
    const a = extractUniqueVertices(edgeData.positions);
    const b = extractUniqueVertices(edgeData.positions);
    expect(a.vertexCount).toBe(b.vertexCount);
    for (let i = 0; i < a.positions.length; i++) {
      expect(a.positions[i]).toBe(b.positions[i]);
    }
    for (let i = 0; i < a.aRandom.length; i++) {
      expect(a.aRandom[i]).toBe(b.aRandom[i]);
    }
  });
});

import { describe, it, expect } from 'vitest';
import { hashRandomFromPosition } from '../../../src/visual/generators/subdivideEdges';
import { generatePolyhedronEdges } from '../../../src/visual/generators/polyhedraEdges';
import { subdivideEdges } from '../../../src/visual/generators/subdivideEdges';

describe('US-065: Position-based aRandom hashing', () => {
  // --- hashRandomFromPosition shared helper ---

  it('T-065-18: hashRandomFromPosition returns 3-element tuple', () => {
    const result = hashRandomFromPosition(1, 2, 3);
    expect(result).toHaveLength(3);
  });

  it('T-065-19: hashRandomFromPosition values are in [0, 1)', () => {
    const positions = [[0, 0, 0], [1, 0, 0], [0.3, -0.2, 0.15], [-1, -1, -1], [100, 200, 300]];
    for (const [x, y, z] of positions) {
      const [r0, r1, r2] = hashRandomFromPosition(x, y, z);
      expect(r0).toBeGreaterThanOrEqual(0);
      expect(r0).toBeLessThan(1);
      expect(r1).toBeGreaterThanOrEqual(0);
      expect(r1).toBeLessThan(1);
      expect(r2).toBeGreaterThanOrEqual(0);
      expect(r2).toBeLessThan(1);
    }
  });

  it('T-065-20: hashRandomFromPosition is deterministic (same input → same output)', () => {
    const a = hashRandomFromPosition(0.3, -0.1, 0.2);
    const b = hashRandomFromPosition(0.3, -0.1, 0.2);
    expect(a[0]).toBe(b[0]);
    expect(a[1]).toBe(b[1]);
    expect(a[2]).toBe(b[2]);
  });

  it('T-065-21: hashRandomFromPosition produces different values for different positions', () => {
    const a = hashRandomFromPosition(0.1, 0.2, 0.3);
    const b = hashRandomFromPosition(0.4, 0.5, 0.6);
    // At least one component should differ
    const allSame = a[0] === b[0] && a[1] === b[1] && a[2] === b[2];
    expect(allSame).toBe(false);
  });

  it('T-065-22: hashRandomFromPosition returns finite values for all inputs', () => {
    const extremes = [[0, 0, 0], [1e6, 1e6, 1e6], [-1e6, -1e6, -1e6], [NaN, 0, 0]];
    for (const [x, y, z] of extremes) {
      const result = hashRandomFromPosition(x, y, z);
      for (let i = 0; i < 3; i++) {
        // NaN input may produce NaN output, that's acceptable — test non-NaN inputs for finiteness
        if (!Number.isNaN(x) && !Number.isNaN(y) && !Number.isNaN(z)) {
          expect(Number.isFinite(result[i]), `non-finite for (${x},${y},${z})[${i}]`).toBe(true);
        }
      }
    }
  });

  // --- polyhedraEdges.ts uses position-based hashing ---

  it('T-065-23: generatePolyhedronEdges randoms are position-based (same position → same aRandom)', () => {
    const edgeData = generatePolyhedronEdges({ shape: 'icosahedron', seed: 'hash-check' });
    // Icosahedron has shared vertices across edges. Find duplicate positions and verify matching randoms.
    const posToRandoms = new Map<string, number[]>();
    const vertCount = edgeData.edgeCount * 2;
    for (let i = 0; i < vertCount; i++) {
      const key = `${Math.round(edgeData.positions[i * 3] * 1e6)},${Math.round(edgeData.positions[i * 3 + 1] * 1e6)},${Math.round(edgeData.positions[i * 3 + 2] * 1e6)}`;
      const randoms = [edgeData.randoms[i * 3], edgeData.randoms[i * 3 + 1], edgeData.randoms[i * 3 + 2]];
      if (posToRandoms.has(key)) {
        const existing = posToRandoms.get(key)!;
        expect(randoms[0]).toBeCloseTo(existing[0], 5);
        expect(randoms[1]).toBeCloseTo(existing[1], 5);
        expect(randoms[2]).toBeCloseTo(existing[2], 5);
      } else {
        posToRandoms.set(key, randoms);
      }
    }
    // Icosahedron has 12 unique positions but 60 edge endpoints — must have duplicates
    expect(posToRandoms.size).toBe(12);
  });

  it('T-065-24: generatePolyhedronEdges randoms match hashRandomFromPosition', () => {
    const edgeData = generatePolyhedronEdges({ shape: 'tetrahedron', seed: 'hash-match' });
    for (let i = 0; i < edgeData.edgeCount * 2; i++) {
      const x = edgeData.positions[i * 3];
      const y = edgeData.positions[i * 3 + 1];
      const z = edgeData.positions[i * 3 + 2];
      const [r0, r1, r2] = hashRandomFromPosition(x, y, z);
      expect(edgeData.randoms[i * 3]).toBeCloseTo(r0, 5);
      expect(edgeData.randoms[i * 3 + 1]).toBeCloseTo(r1, 5);
      expect(edgeData.randoms[i * 3 + 2]).toBeCloseTo(r2, 5);
    }
  });

  // --- subdivideEdges.ts endpoint aRandom matches edge endpoint aRandom ---

  it('T-065-25: subdivideEdges endpoint aRandom matches edge generator aRandom for shared positions', () => {
    const edgeData = generatePolyhedronEdges({ shape: 'octahedron', seed: 'subdiv-match' });
    const subdivided = subdivideEdges(edgeData.positions, 4);
    // Each original edge becomes 4 sub-segments = 8 vertices.
    // First vertex of first sub-segment should match original edge start.
    for (let e = 0; e < edgeData.edgeCount; e++) {
      const origX = edgeData.positions[e * 6];
      const origY = edgeData.positions[e * 6 + 1];
      const origZ = edgeData.positions[e * 6 + 2];
      const subBase = e * 4 * 2; // subdivisions * 2 verts per sub-segment
      const subX = subdivided.positions[subBase * 3];
      const subY = subdivided.positions[subBase * 3 + 1];
      const subZ = subdivided.positions[subBase * 3 + 2];
      // Positions should match
      expect(subX).toBeCloseTo(origX, 5);
      expect(subY).toBeCloseTo(origY, 5);
      expect(subZ).toBeCloseTo(origZ, 5);
      // aRandom at start of subdivided edge should match edge generator aRandom
      const [r0, r1, r2] = hashRandomFromPosition(origX, origY, origZ);
      expect(subdivided.aRandom[subBase * 3]).toBeCloseTo(r0, 5);
      expect(subdivided.aRandom[subBase * 3 + 1]).toBeCloseTo(r1, 5);
      expect(subdivided.aRandom[subBase * 3 + 2]).toBeCloseTo(r2, 5);
    }
  });
});

import { describe, it, expect } from 'vitest';
import { hashRandomFromPosition } from '../../../src/visual/generators/subdivideEdges';
import { generateGeodesicEdges } from '../../../src/visual/generators/geodesicSphere';
import { generateNestedEdges } from '../../../src/visual/generators/nestedSolids';
import { generateDualEdges } from '../../../src/visual/generators/dualPolyhedra';
import type { PolyhedronEdgeData } from '../../../src/visual/generators/polyhedraEdges';

function verifyPositionBasedRandoms(label: string, data: PolyhedronEdgeData): void {
  const vertCount = data.edgeCount * 2;
  for (let i = 0; i < vertCount; i++) {
    const x = data.positions[i * 3];
    const y = data.positions[i * 3 + 1];
    const z = data.positions[i * 3 + 2];
    const [r0, r1, r2] = hashRandomFromPosition(x, y, z);
    expect(data.randoms[i * 3], `${label} vertex ${i} r0`).toBeCloseTo(r0, 5);
    expect(data.randoms[i * 3 + 1], `${label} vertex ${i} r1`).toBeCloseTo(r1, 5);
    expect(data.randoms[i * 3 + 2], `${label} vertex ${i} r2`).toBeCloseTo(r2, 5);
  }
}

describe('US-065: All generators use position-based aRandom hashing', () => {
  it('T-065-26: geodesicSphere randoms match hashRandomFromPosition', () => {
    const data = generateGeodesicEdges({ level: 1, seed: 'geo-hash-test' });
    verifyPositionBasedRandoms('geodesic', data);
  });

  it('T-065-27: nestedSolids randoms match hashRandomFromPosition', () => {
    const data = generateNestedEdges({ shape: 'icosahedron', layers: 2, seed: 'nested-hash-test' });
    verifyPositionBasedRandoms('nested', data);
  });

  it('T-065-28: dualPolyhedra randoms match hashRandomFromPosition', () => {
    const data = generateDualEdges({ shape: 'icosahedron', seed: 'dual-hash-test' });
    verifyPositionBasedRandoms('dual', data);
  });

  it('T-065-29: geodesicSphere shared vertices have identical aRandom values', () => {
    const data = generateGeodesicEdges({ level: 2, seed: 'geo-dedup-test' });
    const posToRandoms = new Map<string, number[]>();
    const vertCount = data.edgeCount * 2;
    let duplicateCount = 0;
    for (let i = 0; i < vertCount; i++) {
      const key = `${Math.round(data.positions[i * 3] * 1e6)},${Math.round(data.positions[i * 3 + 1] * 1e6)},${Math.round(data.positions[i * 3 + 2] * 1e6)}`;
      const randoms = [data.randoms[i * 3], data.randoms[i * 3 + 1], data.randoms[i * 3 + 2]];
      if (posToRandoms.has(key)) {
        duplicateCount++;
        const existing = posToRandoms.get(key)!;
        expect(randoms[0]).toBeCloseTo(existing[0], 5);
        expect(randoms[1]).toBeCloseTo(existing[1], 5);
        expect(randoms[2]).toBeCloseTo(existing[2], 5);
      } else {
        posToRandoms.set(key, randoms);
      }
    }
    // Geodesic level 2 has 270 edges = 540 endpoints but only 42 unique vertices
    expect(duplicateCount).toBeGreaterThan(0);
  });

  it('T-065-30: all generator randoms remain in [0, 1) range', () => {
    const generators = [
      generateGeodesicEdges({ level: 1, seed: 'range-geo' }),
      generateNestedEdges({ shape: 'octahedron', layers: 3, seed: 'range-nested' }),
      generateDualEdges({ shape: 'dodecahedron', seed: 'range-dual' }),
    ];
    for (const data of generators) {
      for (let i = 0; i < data.randoms.length; i++) {
        expect(data.randoms[i]).toBeGreaterThanOrEqual(0);
        expect(data.randoms[i]).toBeLessThan(1);
      }
    }
  });
});

import { describe, it, expect, vi } from 'vitest';
import * as THREE from 'three';
import { createWireframePolyhedra } from '../../../src/visual/systems/wireframePolyhedra';
import type { VisualParams } from '../../../src/visual/mappings';
import type { FrameState } from '../../../src/visual/types';

const defaultParams: VisualParams = {
  paletteHue: 180,
  paletteSaturation: 0.5,
  cadence: 0.7,
  density: 0.6,
  motionAmplitude: 1.0,
  pointerDisturbance: 0,
  bassEnergy: 0,
  trebleEnergy: 0,
  curveSoftness: 0.5,
  structureComplexity: 0.5,
  noiseFrequency: 1.0,
  radialScale: 1.0,
  twistStrength: 1.0,
  fieldSpread: 1.0,
};

function makeFrame(overrides?: Partial<FrameState & { params: Partial<VisualParams> }>): FrameState {
  return {
    time: 1000,
    delta: 16,
    elapsed: 1000,
    width: 800,
    height: 600,
    params: { ...defaultParams, ...(overrides?.params ?? {}) },
    ...Object.fromEntries(Object.entries(overrides ?? {}).filter(([k]) => k !== 'params')),
  } as FrameState;
}

describe('US-065: Vertex-and-edge topology — paired Points + LineSegments', () => {
  // --- Both mesh types present ---

  it('T-065-31: init() adds both THREE.LineSegments AND THREE.Points to the scene', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra();
    wire.init(scene, 'vertex-edge-seed', defaultParams);
    const lines = scene.children.filter((c) => c instanceof THREE.LineSegments);
    const points = scene.children.filter((c) => c instanceof THREE.Points);
    expect(lines.length).toBeGreaterThanOrEqual(1);
    expect(points.length).toBeGreaterThanOrEqual(1);
  });

  it('T-065-32: default config creates 6 LineSegments AND 6 Points (one per polyhedron)', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra();
    wire.init(scene, 'count-seed', defaultParams);
    const lines = scene.children.filter((c) => c instanceof THREE.LineSegments);
    const points = scene.children.filter((c) => c instanceof THREE.Points);
    expect(lines.length).toBe(6);
    expect(points.length).toBe(6);
  });

  it('T-065-33: maxPolyhedra=3 creates exactly 3 LineSegments AND 3 Points', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 3 });
    wire.init(scene, 'three-pair-seed', defaultParams);
    const lines = scene.children.filter((c) => c instanceof THREE.LineSegments);
    const points = scene.children.filter((c) => c instanceof THREE.Points);
    expect(lines.length).toBe(3);
    expect(points.length).toBe(3);
  });

  // --- Vertex dot geometry ---

  it('T-065-34: Points geometry has position attribute with itemSize 3', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'point-pos-seed', defaultParams);
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    expect(point).toBeDefined();
    const geo = point.geometry as THREE.BufferGeometry;
    const posAttr = geo.getAttribute('position');
    expect(posAttr).toBeDefined();
    expect(posAttr.itemSize).toBe(3);
    expect(posAttr.count).toBeGreaterThan(0);
  });

  it('T-065-35: Points geometry has aRandom attribute with itemSize 3', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'point-random-seed', defaultParams);
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const geo = point.geometry as THREE.BufferGeometry;
    const aRandom = geo.getAttribute('aRandom');
    expect(aRandom).toBeDefined();
    expect(aRandom.itemSize).toBe(3);
  });

  it('T-065-36: Points vertex count is less than LineSegments vertex count (deduplicated)', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'dedup-count-seed', defaultParams);
    const line = scene.children.find((c) => c instanceof THREE.LineSegments) as THREE.LineSegments;
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const lineCount = (line.geometry as THREE.BufferGeometry).getAttribute('position').count;
    const pointCount = (point.geometry as THREE.BufferGeometry).getAttribute('position').count;
    expect(pointCount).toBeLessThan(lineCount);
    expect(pointCount).toBeGreaterThanOrEqual(4); // minimum tetrahedron = 4 vertices
  });

  // --- Points material ---

  it('T-065-37: Points use ShaderMaterial with vertex and fragment shaders', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'point-shader-seed', defaultParams);
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const mat = point.material as THREE.ShaderMaterial;
    expect(mat).toBeInstanceOf(THREE.ShaderMaterial);
    expect(mat.vertexShader.length).toBeGreaterThan(0);
    expect(mat.fragmentShader.length).toBeGreaterThan(0);
  });

  it('T-065-38: Points material is transparent with AdditiveBlending and depthWrite disabled', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'point-blend-seed', defaultParams);
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const mat = point.material as THREE.ShaderMaterial;
    expect(mat.transparent).toBe(true);
    expect(mat.depthWrite).toBe(false);
    expect(mat.blending).toBe(THREE.AdditiveBlending);
  });

  it('T-065-39: Points material has uBasePointSize uniform (edges material does not)', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'pointsize-seed', defaultParams);
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const pointMat = point.material as THREE.ShaderMaterial;
    expect(pointMat.uniforms.uBasePointSize).toBeDefined();
    expect(typeof pointMat.uniforms.uBasePointSize.value).toBe('number');

    const line = scene.children.find((c) => c instanceof THREE.LineSegments) as THREE.LineSegments;
    const lineMat = line.material as THREE.ShaderMaterial;
    expect(lineMat.uniforms.uBasePointSize).toBeUndefined();
  });

  it('T-065-40: Points material declares audio-reactive uniforms', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'point-uniforms-seed', defaultParams);
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const mat = point.material as THREE.ShaderMaterial;
    const requiredUniforms = [
      'uTime', 'uBassEnergy', 'uTrebleEnergy', 'uOpacity',
      'uMotionAmplitude', 'uPaletteHue', 'uPaletteSaturation',
      'uFogNear', 'uFogFar', 'uBasePointSize',
    ];
    for (const u of requiredUniforms) {
      expect(mat.uniforms[u], `missing uniform ${u}`).toBeDefined();
    }
  });

  it('T-065-41: Points vertex shader includes noise3d declarations (snoise or fbm3)', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'point-noise-seed', defaultParams);
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const mat = point.material as THREE.ShaderMaterial;
    expect(mat.vertexShader).toMatch(/snoise|fbm3/);
  });

  it('T-065-42: Points vertex shader declares gl_PointSize', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'pointsize-shader-seed', defaultParams);
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const mat = point.material as THREE.ShaderMaterial;
    expect(mat.vertexShader).toMatch(/gl_PointSize/);
  });

  it('T-065-43: Points fragment shader uses gl_PointCoord for soft circular shape', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'pointcoord-seed', defaultParams);
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const mat = point.material as THREE.ShaderMaterial;
    expect(mat.fragmentShader).toMatch(/gl_PointCoord/);
  });

  // --- Position and rotation pairing ---

  it('T-065-44: paired Points and LineSegments share the same world position', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 3 });
    wire.init(scene, 'pair-position-seed', defaultParams);
    const lines = scene.children.filter((c) => c instanceof THREE.LineSegments) as THREE.LineSegments[];
    const points = scene.children.filter((c) => c instanceof THREE.Points) as THREE.Points[];
    expect(lines.length).toBe(points.length);
    for (let i = 0; i < lines.length; i++) {
      expect(points[i].position.x).toBe(lines[i].position.x);
      expect(points[i].position.y).toBe(lines[i].position.y);
      expect(points[i].position.z).toBe(lines[i].position.z);
    }
  });

  it('T-065-45: paired Points and LineSegments share the same rotation', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 3 });
    wire.init(scene, 'pair-rotation-seed', defaultParams);
    const lines = scene.children.filter((c) => c instanceof THREE.LineSegments) as THREE.LineSegments[];
    const points = scene.children.filter((c) => c instanceof THREE.Points) as THREE.Points[];
    for (let i = 0; i < lines.length; i++) {
      expect(points[i].rotation.x).toBe(lines[i].rotation.x);
      expect(points[i].rotation.y).toBe(lines[i].rotation.y);
      expect(points[i].rotation.z).toBe(lines[i].rotation.z);
    }
  });

  // --- draw() updates both materials ---

  it('T-065-46: draw() updates uniforms on both LineSegments AND Points materials', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 2 });
    wire.init(scene, 'draw-both-seed', defaultParams);
    wire.draw(scene, makeFrame({ elapsed: 5000, params: { ...defaultParams, bassEnergy: 0.8 } }));

    const lines = scene.children.filter((c) => c instanceof THREE.LineSegments) as THREE.LineSegments[];
    const points = scene.children.filter((c) => c instanceof THREE.Points) as THREE.Points[];

    for (const line of lines) {
      const mat = line.material as THREE.ShaderMaterial;
      expect(mat.uniforms.uBassEnergy.value).toBe(0.8);
      expect(mat.uniforms.uTime.value).toBe(5000);
    }
    for (const point of points) {
      const mat = point.material as THREE.ShaderMaterial;
      expect(mat.uniforms.uBassEnergy.value).toBe(0.8);
      expect(mat.uniforms.uTime.value).toBe(5000);
    }
  });

  it('T-065-47: draw() does not throw with valid FrameState', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra();
    wire.init(scene, 'draw-safe-seed', defaultParams);
    expect(() => wire.draw(scene, makeFrame())).not.toThrow();
  });

  // --- setOpacity ---

  it('T-065-48: setOpacity updates uOpacity on both LineSegments AND Points materials', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 2 });
    wire.init(scene, 'opacity-both-seed', defaultParams);
    wire.setOpacity!(0.3);

    const lines = scene.children.filter((c) => c instanceof THREE.LineSegments) as THREE.LineSegments[];
    const points = scene.children.filter((c) => c instanceof THREE.Points) as THREE.Points[];
    for (const line of lines) {
      expect((line.material as THREE.ShaderMaterial).uniforms.uOpacity.value).toBe(0.3);
    }
    for (const point of points) {
      expect((point.material as THREE.ShaderMaterial).uniforms.uOpacity.value).toBe(0.3);
    }
  });

  // --- cleanup ---

  it('T-065-49: cleanup() removes all LineSegments AND Points from scene', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 3 });
    wire.init(scene, 'cleanup-both-seed', defaultParams);
    expect(scene.children.filter((c) => c instanceof THREE.LineSegments).length).toBe(3);
    expect(scene.children.filter((c) => c instanceof THREE.Points).length).toBe(3);

    wire.cleanup!();

    expect(scene.children.filter((c) => c instanceof THREE.LineSegments).length).toBe(0);
    expect(scene.children.filter((c) => c instanceof THREE.Points).length).toBe(0);
  });

  it('T-065-50: cleanup() disposes geometry and material for both mesh types', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 2 });
    wire.init(scene, 'dispose-both-seed', defaultParams);

    const lines = scene.children.filter((c) => c instanceof THREE.LineSegments) as THREE.LineSegments[];
    const points = scene.children.filter((c) => c instanceof THREE.Points) as THREE.Points[];

    const geoSpies = [...lines, ...points].map((m) => vi.spyOn(m.geometry, 'dispose'));
    const matSpies = [...lines, ...points].map((m) => vi.spyOn(m.material as THREE.Material, 'dispose'));

    wire.cleanup!();

    for (const spy of geoSpies) {
      expect(spy).toHaveBeenCalled();
    }
    for (const spy of matSpies) {
      expect(spy).toHaveBeenCalled();
    }
  });

  it('T-065-51: cleanup after init with no draws does not throw', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra();
    wire.init(scene, 'early-cleanup-seed', defaultParams);
    expect(() => wire.cleanup!()).not.toThrow();
    expect(scene.children.filter((c) => c instanceof THREE.Points).length).toBe(0);
    expect(scene.children.filter((c) => c instanceof THREE.LineSegments).length).toBe(0);
  });

  // --- No scene leaks ---

  it('T-065-52: multiple draw calls do not leak objects into the scene', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra();
    wire.init(scene, 'leak-seed', defaultParams);
    const childCount = scene.children.length;
    for (let i = 0; i < 10; i++) {
      wire.draw(scene, makeFrame({ elapsed: i * 100 }));
    }
    expect(scene.children.length).toBe(childCount);
  });

  // --- Deformation pipeline identity ---

  it('T-065-53: Points and LineSegments vertex shaders share the same deformation uniforms', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1 });
    wire.init(scene, 'deform-uniform-seed', defaultParams);
    const line = scene.children.find((c) => c instanceof THREE.LineSegments) as THREE.LineSegments;
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const lineMat = line.material as THREE.ShaderMaterial;
    const pointMat = point.material as THREE.ShaderMaterial;

    // All deformation-related uniforms must be present on both
    const deformUniforms = [
      'uTime', 'uBassEnergy', 'uTrebleEnergy', 'uMotionAmplitude',
      'uNoiseFrequency', 'uRadialScale', 'uTwistStrength', 'uFieldSpread',
      'uBreathScale', 'uNoiseOctaves', 'uDisplacementScale',
    ];
    for (const u of deformUniforms) {
      expect(lineMat.uniforms[u], `edge missing ${u}`).toBeDefined();
      expect(pointMat.uniforms[u], `vertex missing ${u}`).toBeDefined();
    }
  });

  // --- Determinism ---

  it('T-065-54: same seed produces same number of LineSegments and Points (deterministic)', () => {
    const sceneA = new THREE.Scene();
    const a = createWireframePolyhedra();
    a.init(sceneA, 'det-seed', defaultParams);
    const linesA = sceneA.children.filter((c) => c instanceof THREE.LineSegments).length;
    const pointsA = sceneA.children.filter((c) => c instanceof THREE.Points).length;

    const sceneB = new THREE.Scene();
    const b = createWireframePolyhedra();
    b.init(sceneB, 'det-seed', defaultParams);
    const linesB = sceneB.children.filter((c) => c instanceof THREE.LineSegments).length;
    const pointsB = sceneB.children.filter((c) => c instanceof THREE.Points).length;

    expect(linesA).toBe(linesB);
    expect(pointsA).toBe(pointsB);
  });

  // --- Privacy ---

  it('T-065-55: no localStorage or cookie access during init/draw with vertex-edge topology', () => {
    const lsSpy = vi.spyOn(Storage.prototype, 'getItem');
    const cookieSpy = vi.spyOn(document, 'cookie', 'get');
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra();
    wire.init(scene, 'privacy-vertex-seed', defaultParams);
    wire.draw(scene, makeFrame());
    expect(lsSpy).not.toHaveBeenCalled();
    expect(cookieSpy).not.toHaveBeenCalled();
  });

  // --- Finite values ---

  it('T-065-56: all Points position values are finite', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 3 });
    wire.init(scene, 'finite-point-seed', defaultParams);
    const points = scene.children.filter((c) => c instanceof THREE.Points) as THREE.Points[];
    for (const point of points) {
      const pos = (point.geometry as THREE.BufferGeometry).getAttribute('position');
      for (let v = 0; v < pos.count * 3; v++) {
        expect(Number.isFinite((pos.array as Float32Array)[v])).toBe(true);
      }
    }
  });

  it('T-065-57: all uniform values remain finite after draw with extreme audio params', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra();
    wire.init(scene, 'finite-uniform-seed', defaultParams);
    wire.draw(scene, makeFrame({ elapsed: 10000, params: { ...defaultParams, bassEnergy: 1.0, trebleEnergy: 1.0, motionAmplitude: 1.0 } }));
    const points = scene.children.filter((c) => c instanceof THREE.Points) as THREE.Points[];
    for (const point of points) {
      const mat = point.material as THREE.ShaderMaterial;
      for (const [name, uniform] of Object.entries(mat.uniforms)) {
        if (typeof uniform.value === 'number') {
          expect(Number.isFinite(uniform.value), `uniform ${name} is not finite`).toBe(true);
        }
      }
    }
  });

  // --- Generation modes produce paired meshes ---

  it('T-065-58: all generation modes produce paired Points + LineSegments across seed sweep', () => {
    for (let i = 0; i < 20; i++) {
      const scene = new THREE.Scene();
      const wire = createWireframePolyhedra({ maxPolyhedra: 1, maxEdgesPerShape: 1920 });
      wire.init(scene, `mode-pair-sweep-${i}`, defaultParams);
      const lines = scene.children.filter((c) => c instanceof THREE.LineSegments);
      const points = scene.children.filter((c) => c instanceof THREE.Points);
      expect(lines.length).toBe(1);
      expect(points.length).toBe(1);
      wire.cleanup!();
    }
  });
});

import { describe, it, expect } from 'vitest';
import * as THREE from 'three';
import { createWireframePolyhedra } from '../../../src/visual/systems/wireframePolyhedra';
import type { VisualParams } from '../../../src/visual/mappings';
import type { FrameState } from '../../../src/visual/types';

const defaultParams: VisualParams = {
  paletteHue: 180,
  paletteSaturation: 0.5,
  cadence: 0.7,
  density: 0.6,
  motionAmplitude: 1.0,
  pointerDisturbance: 0,
  bassEnergy: 0,
  trebleEnergy: 0,
  curveSoftness: 0.5,
  structureComplexity: 0.5,
  noiseFrequency: 1.0,
  radialScale: 1.0,
  twistStrength: 1.0,
  fieldSpread: 1.0,
};

function makeFrame(overrides?: Partial<FrameState & { params: Partial<VisualParams> }>): FrameState {
  return {
    time: 1000,
    delta: 16,
    elapsed: 1000,
    width: 800,
    height: 600,
    params: { ...defaultParams, ...(overrides?.params ?? {}) },
    ...Object.fromEntries(Object.entries(overrides ?? {}).filter(([k]) => k !== 'params')),
  } as FrameState;
}

describe('US-065: Electric arc mode with vertex-edge topology', () => {
  it('T-065-59: electric arc mode creates both Points and LineSegments', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 2, enableElectricArc: true, arcSubdivisions: 5 });
    wire.init(scene, 'arc-pair-seed', defaultParams);
    const lines = scene.children.filter((c) => c instanceof THREE.LineSegments);
    const points = scene.children.filter((c) => c instanceof THREE.Points);
    expect(lines.length).toBe(2);
    expect(points.length).toBe(2);
  });

  it('T-065-60: arc mode LineSegments have subdivided geometry (more vertices than Points)', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1, enableElectricArc: true, arcSubdivisions: 5 });
    wire.init(scene, 'arc-subdiv-seed', defaultParams);
    const line = scene.children.find((c) => c instanceof THREE.LineSegments) as THREE.LineSegments;
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const lineCount = (line.geometry as THREE.BufferGeometry).getAttribute('position').count;
    const pointCount = (point.geometry as THREE.BufferGeometry).getAttribute('position').count;
    // Subdivided edges have many more vertices than unique polyhedron vertices
    expect(lineCount).toBeGreaterThan(pointCount * 2);
  });

  it('T-065-61: arc mode vertex dots use standard wireframeVertex shaders (not arc shaders)', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1, enableElectricArc: true, arcSubdivisions: 5 });
    wire.init(scene, 'arc-shader-seed', defaultParams);
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const mat = point.material as THREE.ShaderMaterial;
    // Vertex dot shader should NOT have arc-specific uniforms
    expect(mat.uniforms.uArcIntensity).toBeUndefined();
    // But should have point-specific uniforms
    expect(mat.uniforms.uBasePointSize).toBeDefined();
  });

  it('T-065-62: arc mode LineSegments have arc-specific attributes (aEdgeParam, aEdgeTangent)', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 1, enableElectricArc: true, arcSubdivisions: 5 });
    wire.init(scene, 'arc-attr-seed', defaultParams);
    const line = scene.children.find((c) => c instanceof THREE.LineSegments) as THREE.LineSegments;
    const lineGeo = line.geometry as THREE.BufferGeometry;
    expect(lineGeo.getAttribute('aEdgeParam')).toBeDefined();
    expect(lineGeo.getAttribute('aEdgeTangent')).toBeDefined();

    // Points should NOT have arc attributes
    const point = scene.children.find((c) => c instanceof THREE.Points) as THREE.Points;
    const pointGeo = point.geometry as THREE.BufferGeometry;
    expect(pointGeo.getAttribute('aEdgeParam')).toBeUndefined();
    expect(pointGeo.getAttribute('aEdgeTangent')).toBeUndefined();
  });

  it('T-065-63: arc mode draw() does not throw', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 2, enableElectricArc: true, arcSubdivisions: 5 });
    wire.init(scene, 'arc-draw-seed', defaultParams);
    expect(() => wire.draw(scene, makeFrame({ elapsed: 1000, params: { ...defaultParams, bassEnergy: 0.7, trebleEnergy: 0.5 } }))).not.toThrow();
  });

  it('T-065-64: arc mode cleanup() removes all Points and LineSegments', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 3, enableElectricArc: true, arcSubdivisions: 5 });
    wire.init(scene, 'arc-cleanup-seed', defaultParams);
    wire.cleanup!();
    expect(scene.children.filter((c) => c instanceof THREE.LineSegments).length).toBe(0);
    expect(scene.children.filter((c) => c instanceof THREE.Points).length).toBe(0);
  });

  it('T-065-65: arc mode paired meshes share the same position and rotation', () => {
    const scene = new THREE.Scene();
    const wire = createWireframePolyhedra({ maxPolyhedra: 2, enableElectricArc: true, arcSubdivisions: 5 });
    wire.init(scene, 'arc-pair-pos-seed', defaultParams);
    const lines = scene.children.filter((c) => c instanceof THREE.LineSegments) as THREE.LineSegments[];
    const points = scene.children.filter((c) => c instanceof THREE.Points) as THREE.Points[];
    for (let i = 0; i < lines.length; i++) {
      expect(points[i].position.x).toBe(lines[i].position.x);
      expect(points[i].position.y).toBe(lines[i].position.y);
      expect(points[i].position.z).toBe(lines[i].position.z);
      expect(points[i].rotation.x).toBe(lines[i].rotation.x);
      expect(points[i].rotation.y).toBe(lines[i].rotation.y);
      expect(points[i].rotation.z).toBe(lines[i].rotation.z);
    }
  });
});

